async function main() {
  console.log('Updating lessons 1-40 with expanded descriptions and functionality...');

  for (const lesson of lessonsData) {
    const result = await prisma.lesson.updateMany({
      where: { order: lesson.order },
      data: {
        ruDescription: lesson.ruDescription,
        uzDescription: lesson.uzDescription,
        ruFunctionality: lesson.ruFunctionality,
        uzFunctionality: lesson.uzFunctionality,
      },
    });
    console.log(`Updated lesson ${lesson.order} (${result.count} record(s))`);
  }

  console.log('Done! All 40 lessons have been updated.');
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
